const fs = require('fs');
const path = require('path');

const ASSETS_ROOT = path.join('C:/Users/derec/Desktop/mini-ko assets');
const OUTPUT_PATH = path.join('C:/Users/derec/dev/miniko-tauri/public/manifest.json');

// Load animation bounds metadata (generated by optimize-animations.js)
const animationBounds = (() => {
  try {
    const boundsPath = path.join(ASSETS_ROOT, 'animation-bounds.json');
    return JSON.parse(fs.readFileSync(boundsPath, 'utf-8'));
  } catch {
    console.warn('No animation-bounds.json found, animations will use full size');
    return { animations: [] };
  }
})();

// Load BC compression metadata (generated by compress-animations tool)
const bcMetadata = (() => {
  try {
    const bcPath = path.join(ASSETS_ROOT, 'bc-metadata.json');
    return JSON.parse(fs.readFileSync(bcPath, 'utf-8'));
  } catch {
    console.warn('No bc-metadata.json found, animations will use PNG decode fallback');
    return { frames: [] };
  }
})();

function deriveId(rawName) {
  let id = rawName;
  id = id.replace(/\.\w+$/, '');
  id = id.replace(/\s*\([^)]*\)/g, '');
  id = id.replace(/\s*\[[^\]]*\]/g, '');
  id = id.toLowerCase();
  id = id.replace(/[-\s]+/g, '_');
  id = id.replace(/&/g, '_and_');
  id = id.replace(/_+/g, '_');
  id = id.replace(/^_|_$/g, '');
  return id;
}

function deriveName(id) {
  return id.replace(/_/g, ' ').replace(/\b\w/g, (c) => c.toUpperCase());
}

function isNumericPng(filename) {
  return /^\d+\.png$/i.test(filename);
}

function isAnimationFrame(filename) {
  return /^.+_\d{5,}\.png$/i.test(filename);
}

function parseLayerNum(folderName) {
  const match = folderName.match(/^(\d+)\./);
  return match ? parseInt(match[1], 10) : 0;
}

function normPath(p) {
  return p.split(path.sep).join('/');
}

function classifyAsset(fullPath, relativePath, entryName) {
  const stat = fs.statSync(fullPath);

  if (stat.isFile() && entryName.toLowerCase().endsWith('.svg')) {
    const id = deriveId(entryName);
    return { id, name: deriveName(id), type: 'svg', path: normPath(relativePath) };
  }

  if (stat.isFile() && entryName.toLowerCase().endsWith('.png')) {
    const id = deriveId(entryName);
    return { id, name: deriveName(id), type: 'png', path: normPath(relativePath) };
  }

  if (stat.isDirectory()) {
    const contents = fs.readdirSync(fullPath);
    const subDirs = contents.filter((c) => c !== 'optimized' && fs.statSync(path.join(fullPath, c)).isDirectory());
    const pngFiles = contents.filter((c) => c.toLowerCase().endsWith('.png') && fs.statSync(path.join(fullPath, c)).isFile());

    if (subDirs.length > 0) {
      const sorted = subDirs.slice().sort();
      const firstSubContents = fs.readdirSync(path.join(fullPath, sorted[0]));
      const framePngs = firstSubContents.filter((f) => f.toLowerCase().endsWith('.png') && isAnimationFrame(f));

      if (framePngs.length > 0) {
        let hasOptimized = false;
        const subLayers = sorted.map((sd) => {
          const sdPath = path.join(fullPath, sd);
          const sdContents = fs.readdirSync(sdPath);
          const sdFrames = sdContents.filter((f) => f.toLowerCase().endsWith('.png')).sort();
          // Extract the prefix from first frame (e.g. "butterflybase" from "butterflybase_00000.png")
          const firstFrame = sdFrames[0] || '';
          const prefixMatch = firstFrame.match(/^(.+)_\d{5,}\.png$/i);
          const prefix = prefixMatch ? prefixMatch[1] : sd;

          // Check for animation bounds data
          const sdRelPath = path.relative(ASSETS_ROOT, sdPath).replace(/\\/g, '/');
          const boundsInfo = animationBounds.animations.find(a => a.path === sdRelPath);

          // Check if optimized folder exists
          const optimizedDir = path.join(sdPath, 'optimized');
          const hasOptDir = fs.existsSync(optimizedDir);
          if (hasOptDir && boundsInfo) hasOptimized = true;

          const subLayer = { name: sd, frameCount: sdFrames.length, prefix };
          if (boundsInfo) {
            subLayer.bounds = {
              width: boundsInfo.croppedWidth,
              height: boundsInfo.croppedHeight,
              offsetX: boundsInfo.offsetX,
              offsetY: boundsInfo.offsetY
            };
          }
          // Look up BC compression metadata for this sublayer
          const assetRelPath = normPath(relativePath);
          const bcInfo = bcMetadata.frames.find(
            b => b.animRelPath === assetRelPath && b.subName === sd
          );
          if (bcInfo) {
            subLayer.alphaOnly = bcInfo.alphaOnly;
            subLayer.bcFile = bcInfo.bcFile;
            subLayer.bcWidth = bcInfo.width;
            subLayer.bcHeight = bcInfo.height;
          }
          return subLayer;
        });
        const id = deriveId(entryName);
        // Use optimized path if available
        const assetPath = hasOptimized ? normPath(relativePath) : normPath(relativePath);
        return { id, name: deriveName(id), type: 'png-animation', path: assetPath, subLayers };
      }
    }

    if (pngFiles.length > 0 && pngFiles.some((f) => isAnimationFrame(f))) {
      const framePngs = pngFiles.filter((f) => isAnimationFrame(f)).sort();
      const firstFrame = framePngs[0] || '';
      const prefixMatch = firstFrame.match(/^(.+)_\d{5,}\.png$/i);
      const prefix = prefixMatch ? prefixMatch[1] : entryName;
      const id = deriveId(entryName);
      return { id, name: deriveName(id), type: 'png-animation', path: normPath(relativePath), subLayers: [{ name: entryName, frameCount: framePngs.length, prefix }] };
    }

    if (pngFiles.length > 0) {
      const numericPngs = pngFiles.filter((f) => isNumericPng(f));
      const id = deriveId(entryName);
      return { id, name: deriveName(id), type: 'png-stack', path: normPath(relativePath), subLayerCount: numericPngs.length };
    }
  }

  return null;
}

function generateManifest() {
  const layerFolders = fs.readdirSync(ASSETS_ROOT).filter((f) => {
    return fs.statSync(path.join(ASSETS_ROOT, f)).isDirectory() && /^\d+\./.test(f);
  });

  layerFolders.sort((a, b) => parseLayerNum(a) - parseLayerNum(b));

  const layers = layerFolders.map((layerFolder) => {
    const layerNum = parseLayerNum(layerFolder);
    const layerPath = path.join(ASSETS_ROOT, layerFolder);
    const contents = fs.readdirSync(layerPath);

    const directPngs = contents.filter((c) => c.toLowerCase().endsWith('.png') && fs.statSync(path.join(layerPath, c)).isFile());
    const directNumericPngs = directPngs.filter((f) => isNumericPng(f));
    const directSvgs = contents.filter((c) => c.toLowerCase().endsWith('.svg') && fs.statSync(path.join(layerPath, c)).isFile());
    const subfolders = contents.filter((c) => c !== 'optimized' && fs.statSync(path.join(layerPath, c)).isDirectory());

    const assets = [];

    if (directNumericPngs.length > 0 && directSvgs.length === 0 && subfolders.length === 0) {
      const layerBaseName = layerFolder.replace(/^\d+\.\s*/, '');
      const id = deriveId(layerBaseName);
      assets.push({ id, name: deriveName(id), type: 'png-stack', path: normPath(layerFolder), subLayerCount: directNumericPngs.length });

      const nonNumericPngs = directPngs.filter((f) => isNumericPng(f) === false);
      for (const png of nonNumericPngs) {
        const pngId = deriveId(png);
        assets.push({ id: pngId, name: deriveName(pngId), type: 'png', path: normPath(layerFolder + '/' + png) });
      }
    } else {
      for (const entry of contents) {
        const fullEntryPath = path.join(layerPath, entry);
        const relativePath = path.join(layerFolder, entry);
        const asset = classifyAsset(fullEntryPath, relativePath, entry);
        if (asset) assets.push(asset);
      }
      assets.sort((a, b) => a.id.localeCompare(b.id, undefined, { numeric: true }));
    }

    return { layerNum, folderName: layerFolder, assets };
  });

  return { layers };
}

const manifest = generateManifest();
const json = JSON.stringify(manifest, null, 2);
fs.writeFileSync(OUTPUT_PATH, json, 'utf-8');

let totalAssets = 0, svgCount = 0, pngStackCount = 0, pngAnimCount = 0, pngCount = 0;
for (const layer of manifest.layers) {
  for (const asset of layer.assets) {
    totalAssets++;
    if (asset.type === 'svg') svgCount++;
    else if (asset.type === 'png-stack') pngStackCount++;
    else if (asset.type === 'png-animation') pngAnimCount++;
    else if (asset.type === 'png') pngCount++;
  }
}

console.log('Manifest generated: ' + OUTPUT_PATH);
console.log('Layers: ' + manifest.layers.length);
console.log('Total assets: ' + totalAssets);
console.log('  SVG: ' + svgCount);
console.log('  PNG-stack: ' + pngStackCount);
console.log('  PNG-animation: ' + pngAnimCount);
console.log('  PNG (standalone): ' + pngCount);
